    surface: { etch: { m: "5% HF × 60 sec", d: "Feldspathic = same etch time as Empress (60s, NOT 20s like LS₂)", w: "Do NOT use e.max/Tessera timing (20s) — feldspathic needs full 60s", refs: ["sundfeld-2018","neis-2015"] }, abrasion: { m: "Not primary — HF standard for feldspathic", refs: [] }, clean: ["Rinse thoroughly","Ultrasonic × 5 min","Steam","Ivoclean if contaminated"], primer: { best: "2-Bottle Silane", mechanism: "Silane → feldspathic glass matrix. Extensive SiO₂ content = excellent silane bonding substrate.", conflict: true, refs: ["shen-2004","lung-2012","sattabanasuk-2016"] }, laser: true, laserNote: "Er:YAG under research for feldspathic" },
    cement: { pref: [{ t: "LC resin cement", ex: "Variolink LC, NX3 LC, RelyX Veneer", n: "Veneers/thin inlays — primary use. Best color stability.", cure: "20s" },{ t: "DC resin cement", ex: "Variolink DC, Panavia V5", n: "Anterior crowns, limited light", dc: "DC activator" }], avoid: ["SA","RMGI","Conventional cement — MUST be adhesively bonded"], special: "Per Vita/Straumann data sheet: 154 ± 15 MPa flexural strength, E = 45 GPa. ADHESIVE CEMENTATION MANDATORY for inlays/onlays/veneers — self-adhesive acceptable for crowns only per IFU. HF 5% etch 60 seconds (feldspathic requires longer etch than LS₂) → silane → adhesive resin cement. Per Compendium (Blatz & Conejo 2022): feldspathic and leucite ceramics require 60 sec HF etch for ideal micromechanical retention. SARCs should NOT be used for ultrathin feldspathic veneers (PMC systematic review). Longest CAD/CAM clinical track record: >25 years, millions of restorations, >90% success rates for inlays/onlays/crowns in clinical studies (Vita data). Otto & Mormann (IJCD 2015): 12-year data on posterior Mark II crowns. No crystallization required — insert after milling + polish. Optional stain/glaze firing available but not mandatory.", refs: [] },
    tooth: { etch: "Selective enamel 15–30s — max enamel coverage critical", adh: [{ s: "Total-etch 3-step (gold standard for veneers)", ex: "OptiBond FL", steps: ["Full etch → primer → adhesive → cure"], dc: "Inherently DC" },{ s: "Selective etch + Universal", ex: "Adhese Universal, Clearfil UBQ2", steps: ["Sel etch enamel → rinse → blot","Adhesive scrub 20s → cure"], dc: "DC activator per system" }], contam: { saliva: "Re-etch, re-bond", tryIn: "Peridex/Ivoclean → re-silanate", blood: "Ivoclean → re-silanate" }, refs: ["vanmeerbeek-2020","peumans-2012"] }
