export const POST_CORE = [

  // ─── CLINICAL DECISION: FERRULE FIRST ───

  { id: "ferrule-protocol", name: "Ferrule Assessment Protocol", mfr: "N/A — Clinical Decision", cat: "Post/Core — Clinical Decision",
    composition: "Not a product — this is the FIRST clinical decision before any post/core. Per Naumann 2018 (J Endod) SR: 'Ferrule comes first. Post is second!' — 7 of 8 clinical studies showed NO positive effect of post placement, while the ferrule effect was consistently supported.",
    indications: ["EVERY endodontically treated tooth being restored indirectly","Assessment BEFORE deciding on post type or core material"],
    notes: "Per Hajeer 2026 SR+MA: ferrule ≥2mm significantly improved fracture resistance (MD +165 N, 95% CI: 110–215) AND clinical survival (RR 1.34, 95% CI: 1.12–1.59). Per Jardim 2025 SR+MA (13 RCTs): posts significantly reduced failure for INDIRECT restorations only (RR 0.44, p<0.001) — NO benefit for direct restorations (RR 0.63, p=0.27). Posts help, but only for crowns, and only when ferrule is also present.\n\nDECISION TREE:\n• ≥2mm circumferential ferrule + ≥2 coronal walls → Post OPTIONAL, direct core may suffice\n• ≥2mm ferrule but <2 walls → Fiber post recommended for retention\n• <2mm ferrule → Post + crown mandatory; incomplete ferrule (≥2 opposing walls) still better than none\n• No ferrule → Worst prognosis regardless of post type; consider extraction vs strategic reinforcement\n\nPer Juloski 2012 (J Endod): minimum 1.5–2mm circumferential ferrule provides optimal biomechanics. Per Dong 2024 SR: incomplete ferrule (≥2 opposing walls) is significantly better than no ferrule.\n\nPer Naumann 2018: no restorative strategy matches the biomechanical reinforcement of natural dentin ferrule. Preserve tooth structure aggressively.",
    steps: ["Measure remaining coronal dentin height circumferentially after endo access","Assess number of intact walls (4-wall, 3-wall, 2-wall, 1-wall, 0-wall)","If ≥2mm height on all walls: ferrule adequate — post optional for additional retention","If <2mm on any wall: post recommended to improve retention","If no wall ≥2mm: worst prognosis — discuss with patient, consider crown lengthening for ferrule gain","Document ferrule status in treatment notes"],
    special: "Per Naumann 2018 SR (J Endod): the most cited clinical guideline on post necessity — 'Ferrule comes first. Post is second!' 7/8 clinical studies showed no benefit from posts alone; 2/3 studies supported ferrule as the primary determinant of success. Per Hajeer 2026 SR+MA: ferrule ≥2mm provides +165 N fracture resistance AND 1.34× survival improvement — the strongest evidence for any single biomechanical factor in ETT restoration. Per Jardim 2025 SR+MA of 13 RCTs: posts reduce failure for indirect (RR 0.44, p<0.001) but NOT direct restorations (RR 0.63, p=0.27). The evidence is unambiguous: ferrule assessment determines prognosis more than post selection. Per Al-Dabbagh 2024 SR+MA: circumferential ferrule of 1.5–2mm provides optimal biomechanical behavior. Per Dong 2024 SR: incomplete ferrule (≥2 opposing walls) is still significantly better than no ferrule — partial ferrule still has value.", refs: ["naumann-2018-ferrule","hajeer-2026-ferrule-ma","jardim-2025-post-ma"] },

  // ─── POST TYPES ───

  { id: "fiber-post-prefab", name: "Fiber Posts (Prefabricated Glass/Quartz)", mfr: "Various (Coltene, 3M, Ivoclar, Kuraray)", cat: "Post/Core — Fiber Reinforced",
    composition: "Glass or quartz fibers in epoxy or methacrylate resin matrix. Modulus: ~15–40 GPa (closely matches dentin ~18 GPa). Products: ParaPost Fiber Lux (Coltene), RelyX Fiber Post (3M), DT Light SL (VDW), FRC Postec Plus (Ivoclar).",
    indications: ["Endodontically treated teeth requiring post retention (MOST situations)","Anterior and premolar teeth","When adhesive cementation is planned","Tooth-colored restoration (esthetic through ceramic)","≤2 coronal walls remaining (higher survival vs metal at 3–7 yr per Wang 2019)"],
    notes: "BEST OVERALL OUTCOMES per Giok 2023 network MA (25 RCTs): fiber posts are the preferred choice for most clinical situations. Per Tsintsadze 2024 SR+MA: glass fiber posts 92.8% overall survival vs metal 78.1%. Per Wang 2019 SR+MA: fiber posts showed significantly higher survival (RR 0.57, p=0.04) at 3–7 years when ≤2 coronal walls remain. The modulus match (fiber ~15–40 GPa vs dentin ~18 GPa) is the key — failure mode is restorable (debond) rather than catastrophic (root fracture).",
    steps: ["Post space: ≥4–5 mm apical GP seal. Post length should reach middle third of root (Reich 2024: highly significant survival advantage)","Try-in: passive fit mandatory (no binding)","Surface treatment: sandblast 50 μm Al₂O₃ → silane (MANDATORY for resin bond)","Canal prep: irrigate NaOCl → rinse → 99% ethanol rinse (Kosan 2021: +2 MPa bond strength, p=0.016) → dry with paper points","Apply adhesive to canal walls (SE preferred for deep canals — less moisture sensitivity)","Apply DC resin cement: self-adhesive (RelyX Unicem, Panavia SA) for simplicity, OR dual-cure + etch-and-rinse for maximum bond (Pinto 2026)","Seat with finger pressure → light-cure through translucent post + allow DC set","Build core with DC composite"],
    special: "Per Giok 2023 network MA (J Prosthet Dent, 25 RCTs): fiber posts are the preferred post type for most clinical situations — best balance of survival, failure mode, and retreatability. Per Tsintsadze 2024 SR+MA (J Prosthet Dent): glass fiber 92.8% vs metal 78.1% overall survival, though the difference was not statistically significant — the clinical advantage is the FAILURE MODE, not survival rate alone. Per Figueiredo 2015 SR+MA (J Endod): prefabricated metal posts and carbon fiber posts showed 2-fold increase in root fracture incidence vs cast metal and glass fiber posts. Per Wang 2019: fiber posts significantly superior (RR 0.57, p=0.04) when ≤2 walls remain — this is exactly when posts matter most. Per Reich 2024 (J Dent, n=1026): posts reaching middle third of root showed highly significant survival advantage (p<0.001). Per Kosan 2021 (Clin Oral Investig): ethanol (99%) rinse before cementation significantly increased bond strength (16.5 vs 14.5 MPa, p=0.016). Per Pinto 2026: self-adhesive cements achieve predictable adhesion without separate bonding — valuable in deep/complex root canals.", refs: ["giok-2023-fiber-metal-nma","tsintsadze-2024-fiber-metal-ma","figueiredo-2015-root-fracture-ma","reich-2024-post-length","kosan-2021-ethanol-bond","pinto-2026-cement-bondstrength"] },

  { id: "cast-post-core", name: "Cast Post & Core", mfr: "Lab-fabricated", cat: "Post/Core — Cast Metal",
    composition: "Custom wax pattern → cast in noble or base metal alloy. Single-unit post and core. Modulus: ~100–200 GPa (6–11× dentin).",
    indications: ["Oval canals/severe destruction where prefab posts don't fit","Unusual/non-round canal anatomy requiring custom adaptation","Maximum retention needed (metal debonds less than fiber per Giok 2023)","Patient receiving full-coverage metal or PFM restoration"],
    notes: "⚠ MODULUS MISMATCH: 100–200 GPa vs dentin 18 GPa → stress concentration at root apex → catastrophic vertical root fracture risk. Per Giok 2023 network MA: metal posts have BETTER retention (less debonding) but similar root fracture rates to fiber. Per Cloet 2017 (5-year RCT): cast gold vs composite post-core — 85.2% success, 91.5% survival, NO significant difference when teeth had ferrule + ceramic restorations.",
    steps: ["Post space: leave ≥4–5 mm apical GP seal","Impression: direct pattern (Duralay) or indirect (impression post + lab)","Lab: wax → invest → cast → finish","Try-in: PASSIVE fit mandatory","Cementation: ZnPO₄ (thinnest film, gold standard), RMGI, or resin cement","Core: integrated with post (single casting)","Prep for final restoration"],
    special: "Per Giok 2023 network MA (25 RCTs): metal posts showed less debonding than fiber posts but SIMILAR overall survival and root fracture rates. The clinical implication: metal posts are more retentive but this doesn't translate to better outcomes. Per Figueiredo 2015 SR+MA: prefabricated metal posts showed 2× root fracture incidence vs glass fiber — but CAST metal posts (custom-fit) showed comparable root fracture rates to fiber. The distinction matters: cast posts distribute stress better than prefab metal because they fit the canal anatomy precisely. Per Cloet 2017 (5-year controlled clinical trial): cast gold cores vs glass fiber composite cores — no significant differences in success (85.2%) or survival (91.5%) when ALL teeth had ferrule + ceramic restorations. The ferrule equalizes outcomes. Cast posts retain a role for: (1) severely irregular/oval canals where prefab posts don't adapt, (2) minimal coronal structure requiring maximum retention, (3) cases already committed to metal-based restorations.", refs: ["giok-2023-fiber-metal-nma","figueiredo-2015-root-fracture-ma"] },

  // ─── FIBER REINFORCEMENT ───

  { id: "everx-flow", name: "EverX Flow / EverX Posterior (Short Fiber-Reinforced)", mfr: "GC Corporation", cat: "Post/Core — Fiber-Reinforced Composite",
    composition: "Short E-glass fibers (~1–2mm) randomly distributed in Bis-GMA/TEGDMA matrix. EverX Flow: flowable viscosity for base/liner. EverX Posterior: packable body for bulk dentin replacement. Fracture toughness: ~2.3 MPa√m (vs ~1.0–1.5 for conventional DC cores).",
    indications: ["Dentin replacement / base layer in post-endo core build-ups","Structurally compromised teeth — complete restorations without coverage","Cusp replacement","Direct restorations in high-stress posterior teeth","Alternative or complement to Ribbond fiber reinforcement"],
    notes: "Per Bijelic-Donova 2025 SR+MA (23 studies, Oper Dent): short fiber-reinforced composites showed SIGNIFICANTLY higher fracture resistance than conventional composites (p<0.05). Per Säilynoja 2021: fracture toughness 2.3 MPa√m vs 1.0–1.5 for conventional DC materials — fibers effective in stopping crack propagation. Per Jakab 2024 SR: SFRCs can serve as COMPLETE restorations in structurally compromised teeth without full coverage.\n\n⚠ MUST be capped with wear-resistant composite — E-glass fibers exposed to oral environment will degrade. Use as dentin replacement layer UNDER enamel-replacing composite (e.g., Filtek Z250, Clearfil APX).",
    steps: ["Apply adhesive per protocol","Place EverX Flow as base layer (flowable — adapts to cavity floor/fiber post)","For bulk dentin replacement: EverX Posterior in increments up to 4–5 mm","Leave 1.5–2 mm occlusal for wear-resistant capping composite","Cap with conventional packable composite (Filtek Z250, Clearfil APX, etc.)","Light cure each increment 20–40 sec"],
    special: "Per Bijelic-Donova 2025 SR+MA (Oper Dent, 23 studies): the most comprehensive review of SFRCs in structurally compromised teeth — significantly higher fracture resistance than conventional composites. The randomly oriented short E-glass fibers create a 3D crack-arrest network: when a crack encounters a fiber, it must either deflect around it, pull the fiber out, or fracture the fiber — each mechanism absorbs energy that would otherwise propagate the crack. Per Säilynoja 2021 (Polymers): experimental SFRC DC core materials achieved fracture toughness of 2.3 MPa√m — double that of conventional DC core materials like LuxaCore Z (1.0 MPa√m). Per Jakab 2024 SR (Polymers): SFRCs can function as complete restorations without cuspal coverage in structurally compromised teeth — challenging the traditional assumption that post-endo teeth always need full-coverage crowns. Per Albashaireh 2024 (J Dent): in teeth WITH ferrule, Ribbond-reinforced cores achieved significantly higher fracture loads (465 N) than glass fiber post + DC alone (368 N) or DC alone (276 N) — fiber reinforcement of the core itself matters independently of post type.", refs: ["bijelicdonova-2025-frc-sr","kelch-2022-dc-core-properties","albashaireh-2024-ferrule-core"] },

  { id: "ribbond", name: "Ribbond (UHMWPE Fiber Ribbon)", mfr: "Ribbond Inc.", cat: "Post/Core — Fiber Reinforcement",
    composition: "Ultra-high molecular weight polyethylene (UHMWPE) leno-woven ribbon. Lock-stitch weave prevents fraying. Bondable with adhesive + composite. 126% increase in strain capacity vs unreinforced composite (Karbhari 2007).",
    indications: ["Coronal reinforcement of post-endo teeth","Custom fiber network across pulp chamber floor","Periodontal splinting","Direct FPD pontic reinforcement","Composite repair reinforcement"],
    notes: "NOT a post — fiber reinforcement ribbon placed WITHIN composite mass. Creates multi-directional crack arrest network. Per Karbhari 2007 (Dent Mater): 126% increase in strain capacity vs unreinforced composite, with highest consistency in response due to leno-weave architecture. Per Albashaireh 2024 (J Dent): Ribbond-reinforced cores achieved significantly higher fracture loads (465 N) than GFP+DC (368 N) or DC alone (276 N) in teeth WITH ferrule.",
    steps: ["Cut Ribbond to length (handle with cotton pliers — avoid contamination)","Saturate with unfilled resin (bonding agent) — fiber MUST be fully wetted","Apply adhesive to tooth structure per protocol","Place first increment of flowable composite","Embed Ribbond into uncured flowable — press to adapt to cavity floor","Cure through Ribbond 20 sec","Build up with additional composite (EverX base + packable body)","⚠ Fiber must be fully wetted — dry Ribbond becomes an INCLUSION that weakens rather than strengthens"],
    special: "Per Karbhari 2007 (Dent Mater): UHMWPE (Ribbond) vs glass fibers (FibreKor, GlasSpan) — Ribbond provided 126% increase in strain capacity and HIGHEST CONSISTENCY in fracture response due to leno-weave architecture. Glass fibers increased elastic modulus more, but Ribbond provided better damage tolerance and energy absorption. Per Albashaireh 2024 (J Dent): critical finding in teeth with ferrule under ceramic crowns after aging — Ribbond-reinforced cores (465 N) significantly outperformed glass fiber post + DC (368 N) and DC alone (276 N). This means Ribbond reinforcement of the CORE provides a mechanical advantage independent of (and additive to) the post. The leno-weave allows resin infiltration while maintaining fiber integrity — unlike unidirectional fibers, Ribbond arrests cracks from ANY direction. Technique-critical: fiber must be fully wetted with resin before embedding. Dry placement creates an inclusion (weakening defect) rather than reinforcement.", refs: ["karbhari-2007-fiber-architecture","albashaireh-2024-ferrule-core"] },

  // ─── CORE BUILD-UP MATERIALS ───

  { id: "corex-flow", name: "Core·X Flow (Dentsply Sirona)", mfr: "Dentsply Sirona", cat: "Post/Core — DC Core Build-Up",
    composition: "Dual-cure flowable core composite. Automix cartridge. Self-etching adhesive primer included in some kits.",
    indications: ["Core build-up under crowns","Fiber post cementation + core","Standard post-endo core material"],
    notes: "Per Kelch 2022 (Clin Oral Investig): Core·X Flow showed HIGHEST degree of conversion AND Martens hardness after self-polymerization among tested DC cores — meaning it performs best in the deep, light-inaccessible areas where DC matters most. Also highest flexural strength and reliability after light-curing. The self-cure performance is the differentiator: when light can't reach the base of a deep post canal, Core·X Flow's chemical cure produces better mechanical properties than competitors.",
    steps: ["Apply adhesive (Dentsply system: Prime & Bond, or universal adhesive)","If using fiber post: silane-treat post → coat with Core·X Flow → seat","Inject Core·X Flow into canal and onto preparation via automix tip","Light-cure accessible surfaces 20–40 sec","Allow DC set ≥5 min for deep areas","Prep to final crown dimensions"],
    special: "Per Kelch 2022 (Clin Oral Investig): comprehensive comparison of DC core build-up materials — Core·X Flow achieved the highest degree of conversion (DC) and Martens hardness in self-polymerization mode, AND the highest flexural strength and reliability in light-cure mode. This dual superiority is clinically significant: the base of a fiber post canal receives NO light, so the self-cure properties determine mechanical quality at the most critical location. Light-polymerization always produces superior results over self-cure alone in DC materials — Core·X Flow minimizes this gap. ⚠ LuxaCore Z showed lowest fracture toughness (1.0 MPa√m) in same study.", refs: ["kelch-2022-dc-core-properties"] },

  { id: "clearfil-dc-core-plus", name: "Clearfil DC Core Plus", mfr: "Kuraray Noritake", cat: "Post/Core — DC Core Build-Up",
    composition: "Dual-cure composite core. Fluoride-releasing. Automix. Contains MDP monomer for synergy with Clearfil adhesives. Radiopaque.",
    indications: ["Core build-up under crowns","Fiber post cementation + core in one material","Kuraray adhesive system users"],
    notes: "DC = polymerization guaranteed at depth. MDP creates chemical synergy with Clearfil SE Bond 2 / Universal Bond Quick 2 (MDP-calcium nanolayer at dentin interface). Fluoride release at core-dentin margin provides secondary caries protection under crowns. Per Kelch 2022: light-polymerization ALWAYS produces superior mechanical properties vs self-cure alone — light-cure all accessible surfaces before relying on DC set.",
    steps: ["Apply Clearfil SE Bond 2 or Universal Bond Quick 2","If fiber post: sandblast → silane → coat with DC Core Plus","Inject into canal and preparation","Light-cure accessible surfaces 20–40 sec","Wait 4–5 min for full DC set before prep","Prep to final crown dimensions"],
    special: "Per Kelch 2022 (Clin Oral Investig): DC core materials vary significantly in self-cure performance — light-polymerization always produces higher degree of conversion, hardness, and flexural strength. For Clearfil DC Core Plus specifically: the MDP in the formulation creates chemical synergy with Clearfil adhesive systems — the MDP-calcium nanolayer at the dentin interface is a chemical bond that complements the micromechanical hybrid layer. Fluoride release provides long-term caries protection at the vulnerable core-dentin junction beneath the crown margin. Automix cartridge eliminates hand-mixing variability. High radiopacity allows clear distinction between core and tooth on radiographs — essential for re-treatment planning.", refs: ["kelch-2022-dc-core-properties"] },

  { id: "luxacore-z", name: "LuxaCore Z-Dual", mfr: "DMG", cat: "Post/Core — DC Core Build-Up",
    composition: "DC composite core reinforced with nano-zirconia filler. Automix. Shades: blue (visibility), A3 (esthetic), opaque white.",
    indications: ["Core build-up under all-ceramic (A3)","Core under PFM/metal (blue for visibility)","High-strength core situations"],
    notes: "Zirconia nano-filler = higher compressive strength than conventional glass-filled cores. Blue shade makes core-tooth junction visible during crown prep — reduces over-preparation risk. ⚠ Per Kelch 2022 (Clin Oral Investig): LuxaCore Z showed LOWEST fracture toughness among tested DC cores (1.0 MPa√m vs 2.3 for fiber-reinforced materials). Adequate for routine cores but NOT for structurally compromised situations where crack resistance matters — consider EverX Flow or Ribbond reinforcement instead.",
    steps: ["Apply adhesive per protocol","Inject LuxaCore Z-Dual via automix tip","Seat fiber post if indicated","Light-cure 20–40 sec","DC set 5–6 min total before prep","Cuts cleanly with diamonds"],
    special: "Per Kelch 2022 (Clin Oral Investig): LuxaCore Z showed the lowest fracture toughness (1.0 MPa√m) among tested DC core materials. The zirconia nano-filler provides high compressive strength and hardness, but the fracture toughness limitation means cracks propagate more easily through the material once initiated. For routine cores under crowns with adequate ferrule: LuxaCore Z is perfectly adequate — the crown protects the core from direct loading. For structurally compromised teeth or cores that must resist crack propagation: consider fiber-reinforced alternatives (EverX, Ribbond). The blue shade visibility is a genuine clinical advantage — during crown preparation, the color contrast between blue core and yellow dentin prevents inadvertent over-preparation into tooth structure.", refs: ["kelch-2022-dc-core-properties"] },

  { id: "filtek-one-bulk-core", name: "Filtek One Bulk Fill (as Core)", mfr: "Solventum (3M)", cat: "Post/Core — LC Bulk Fill Core",
    composition: "AFM (Advanced Filtek Matrix) with 76 wt% nanocluster filler. 5mm DOC. Single shade. LC only — NOT DC.",
    indications: ["Supragingival core build-ups with full light access","Situations where DC is unnecessary","When single-shade/single-increment simplicity desired"],
    notes: "⚠ LIGHT-CURE ONLY. If ANY part of the core is beyond light reach → it stays uncured → failure. For deep post canals or under opaque restorations: use DC material instead.\n\nPer Chaple Gil 2025 network MA: no significant difference between bulk-fill and incremental techniques for marginal adaptation, fractures, or retention at 6–24 months. Per Loguercio 2023 (5-year RCT): annual failure rate 1.2% bulk-fill vs 1.0% incremental (p=0.35). Per Leinonen 2023: bulk-fill is 59.8% FASTER (186s vs 463s median time).\n\n⚠ Per Kaisarly 2021 (Clin Oral Investig): bulk application showed greater shrinkage vectors and higher debonding tendency at cavity floor — incremental remains gold standard from polymerization shrinkage perspective. Trade-off: faster and clinically equivalent outcomes vs theoretically worse shrinkage mechanics.",
    steps: ["Apply adhesive per protocol","Place Filtek One Bulk Fill up to 5mm","Ensure light access to DEEPEST point","Cure 20 sec (≥800 mW/cm²)","Prep to final crown dimensions","⚠ Can your light reach the deepest material? If NO → use DC core"],
    special: "Per Chaple Gil 2025 network MA (J Esthet Restor Dent): the most comprehensive comparison of bulk-fill vs incremental — no statistically significant differences for marginal adaptation, fractures, or retention at 6, 12, or 24 months. Risk ratios clustered around unity. Per Loguercio 2023 5-year double-blind RCT (Dent Mater): 1.2% vs 1.0% annual failure rate — no significant difference for any parameter. Per Leinonen 2023 (J Dent): 59.8% faster procedure time with better immediate quality (fewer surface porosities, fewer marginal gaps). The evidence supports bulk-fill as clinically equivalent to incremental for core build-ups, with significant time savings. The LC-only limitation is the key constraint: use only when all material is within 5mm of light access.", refs: ["kelch-2022-dc-core-properties"] },
];

